1038	            UiKey::Char('V') => self.set_visual_selection_kind(VisualSelectionKind::Line),
1039	            UiKey::Char('\u{16}') => self.set_visual_selection_kind(VisualSelectionKind::Block),
1040	            UiKey::Char('y') => self.yank_visual_selection(false),
1041	            UiKey::Char('Y') => self.yank_visual_selection(true),
1042	            UiKey::Char('h') | UiKey::Left => self.move_visual_column(-1),
1043	            UiKey::Char('l') | UiKey::Right => self.move_visual_column(1),
1044	            UiKey::Char('j') | UiKey::Down => self.move_visual_row(1),
1045	            UiKey::Char('k') | UiKey::Up => self.move_visual_row(-1),
1046	            UiKey::Char('0') => self.move_visual_to_column(0),
1047	            UiKey::Char('$') => self.move_visual_to_line_end(),
1048	            UiKey::Char('g') => self.pending = Some(PendingKey::G),
1049	            UiKey::Char('G') => {
