649	    fn render_tui_buffer(&self, right_content: &str, prompt: &str, prompt_cursor: usize) -> Buffer {
650	        let backend = TestBackend::new(self.width, self.height);
651	        let mut terminal = Terminal::new(backend).expect("test backend is valid");
652	        terminal
653	            .draw(|frame| {
654	                let area = frame.size();
655	                let body_height = area.height.saturating_sub(1);
656	                let body = Rect::new(area.x, area.y, area.width, body_height);
657	                let bottom = Rect::new(area.x, body_height, area.width, 1);
658	                let layout = self.layout();
659	                let panes = if layout.left_width > 0 {
660	                    Layout::default()
661	                        .direction(Direction::Horizontal)
662	                        .constraints([
663	                            Constraint::Length(layout.left_width),
664	                            Constraint::Length(layout.right_width),
665	                        ])
666	                        .split(body)
667	                } else {
668	                    vec![body]
669	                };
670	
671	                if layout.left_width > 0 {
672	                    frame.render_widget(self.left_widget(), panes[0]);
673	                    frame.render_widget(self.right_widget(right_content), panes[1]);
674	                } else {
675	                    frame.render_widget(self.right_widget(right_content), panes[0]);
676	                }
677	                frame.render_widget(
678	                    Paragraph::new(self.bottom_line(prompt, prompt_cursor)),
679	                    bottom,
680	                );
681	            })
682	            .expect("test backend draw succeeds");
683	        terminal.backend().buffer().clone()
684	    }
