471	    fn continue_escape_sequence(&mut self, byte: u8) -> bool {
472	        let Some(sequence) = self.escape_sequence.as_mut() else {
473	            return false;
474	        };
475	
476	        if sequence.bytes.len() == 1 && byte != b'[' {
477	            let sequence = self
478	                .escape_sequence
479	                .take()
480	                .expect("escape sequence is present");
481	            self.dispatch_pending_escape_if_needed(&sequence);
482	            return false;
483	        }
484	
485	        sequence.bytes.push(byte);
486	        if let Some((key, len)) = parse_key_sequence(&sequence.bytes) {
487	            if len == sequence.bytes.len() {
488	                let sequence = self
489	                    .escape_sequence
490	                    .take()
491	                    .expect("escape sequence is present");
492	                if sequence.escape_dispatched
493	                    && sequence.mode_before == UiMode::Insert
494	                    && self.ui.mode() != UiMode::Insert
495	                {
496	                    let actions = self.handle_ui_key(UiKey::Char('i'));
497	                    self.record_actions(actions);
498	                }
499	                self.handle_input(HarnessInput::Key(key));
500	            }
501	        } else if sequence.bytes.len() > MAX_ESCAPE_SEQUENCE {
502	            let sequence = self
503	                .escape_sequence
504	                .take()
505	                .expect("escape sequence is present");
506	            self.dispatch_pending_escape_if_needed(&sequence);
507	        }
508	
509	        true
510	    }
