532	
533	fn parse_key_sequence(bytes: &[u8]) -> Option<(UiKey, usize)> {
534	    match bytes {
535	        [27, b'[', b'A', ..] => Some((UiKey::Up, 3)),
536	        [27, b'[', b'B', ..] => Some((UiKey::Down, 3)),
537	        [27, b'[', b'C', ..] => Some((UiKey::Right, 3)),
538	        [27, b'[', b'D', ..] => Some((UiKey::Left, 3)),
539	        _ => parse_sgr_mouse_sequence(bytes),
540	    }
541	}
542	
543	fn parse_sgr_mouse_sequence(bytes: &[u8]) -> Option<(UiKey, usize)> {
544	    if !bytes.starts_with(b"\x1b[<") {
545	        return None;
546	    }
547	
548	    let final_index = bytes.iter().position(|byte| matches!(byte, b'M' | b'm'))?;
549	    let final_byte = bytes[final_index];
550	    let body = std::str::from_utf8(&bytes[3..final_index]).ok()?;
551	    let mut parts = body.split(';');
552	    let button = parts.next()?.parse::<u16>().ok()?;
553	    let column = parts.next()?.parse::<u16>().ok()?;
554	    let row = parts.next()?.parse::<u16>().ok()?;
555	    if parts.next().is_some() {
556	        return None;
557	    }
558	
559	    let button_kind = button & !0b0001_1100_u16;
560	    let key = match (button_kind, final_byte) {
561	        (64, b'M') => UiKey::MouseScrollUp { column, row },
562	        (65, b'M') => UiKey::MouseScrollDown { column, row },
563	        (_, b'M' | b'm') if button_kind < 64 && button & 0b11 == 0 => {
564	            UiKey::MouseClick { column, row }
565	        }
566	        _ => return None,
567	    };
568	    Some((key, final_index + 1))
569	}
