581	impl HarnessInput {
582	    fn from_byte(byte: u8) -> Option<Self> {
583	        match byte {
584	            3 => Some(Self::Interrupt),
585	            4 => Some(Self::Quit),
586	            13 | 10 => Some(Self::Enter),
587	            27 => Some(Self::Key(UiKey::Esc)),
588	            23 => Some(Self::Key(UiKey::CtrlW)),
589	            22 => Some(Self::Char('\u{16}')),
590	            8 | 127 => Some(Self::Backspace),
591	            byte if byte.is_ascii_graphic() || byte == b' ' => Some(Self::Char(byte as char)),
592	            _ => None,
593	        }
594	    }
595	}
