1583	fn ordered_rows(selection: VisualSelection) -> (usize, usize) {
1584	    if selection.anchor.row <= selection.cursor.row {
1585	        (selection.anchor.row, selection.cursor.row)
1586	    } else {
1587	        (selection.cursor.row, selection.anchor.row)
1588	    }
