1591	fn selection_columns_for_line(
1592	    selection: VisualSelection,
1593	    row: usize,
1594	    line: &str,
1595	) -> (usize, usize) {
1596	    let line_len = line.chars().count();
1597	    let (start_row, end_row) = ordered_rows(selection);
1598	    if row < start_row || row > end_row {
1599	        return (0, 0);
1600	    }
1601	
1602	    let (start, end) = match selection.kind {
1603	        VisualSelectionKind::Line => (0, line_len),
1604	        VisualSelectionKind::Block => {
1605	            let start = selection.anchor.column.min(selection.cursor.column);
1606	            let end = selection.anchor.column.max(selection.cursor.column) + 1;
1607	            (start, end)
1608	        }
1609	        VisualSelectionKind::Character if selection.anchor.row == selection.cursor.row => {
1610	            let start = selection.anchor.column.min(selection.cursor.column);
1611	            let end = selection.anchor.column.max(selection.cursor.column) + 1;
1612	            (start, end)
1613	        }
1614	        VisualSelectionKind::Character if row == start_row => {
1615	            let start = if selection.anchor.row <= selection.cursor.row {
1616	                selection.anchor.column
1617	            } else {
1618	                selection.cursor.column
1619	            };
1620	            (start, line_len)
1621	        }
1622	        VisualSelectionKind::Character if row == end_row => {
1623	            let end = if selection.anchor.row <= selection.cursor.row {
1624	                selection.cursor.column
1625	            } else {
1626	                selection.anchor.column
1627	            } + 1;
1628	            (0, end)
1629	        }
1630	        VisualSelectionKind::Character => (0, line_len),
1631	    };
1632	
1633	    (start.min(line_len), end.min(line_len))
1634	}
